import json
import os

class UserRepository:
    def __init__(self):
        # Internal store mapping email to user dict
        self.users = {} 

    def add_user(self, name, email):
        if email in self.users:
            return False # User already exists
        self.users[email] = {"name": name, "email": email}
        return True

    def get_user(self, email):
        """Returns user dictionary or None if not found."""
        return self.users.get(email)

class UserStore:
    def __init__(self, db_path):
        self.db_path = db_path

    def save(self, users):
        """Users is expected to be a dict of user data (like self.users from UserRepository)."""
        data = list(users.values())
        with open(self.db_path, 'w') as f:
            json.dump(data, f)

    def load(self):
        """Loads users from the database path."""
        if not os.path.exists(self.db_path):
            return []
        try:
            with open(self.db_path, 'r') as f:
                data = json.load(f)
                # Assuming loaded data is a list of user dicts [{name:.., email:..}, ...]
                # For consistent testing with repository methods, we'll return the list itself.
                return data
        except json.JSONDecodeError:
            return []

